import * as jose from "jose";

const SEMANTIC_PREFIXES = ["core.", "insurance.", "aerospace.", "supply_chain."];

export async function fetchManifest(manifestUrl, { fetchImpl = globalThis.fetch } = {}) {
  const resp = await fetchImpl(manifestUrl, { headers: { Accept: "application/json" } });
  if (!resp.ok) throw new Error(`manifest fetch failed: ${resp.status}`);
  return await resp.json();
}

export async function verifyManifest(manifest, { fetchImpl = globalThis.fetch, signingKeyUrl } = {}) {
  if (!manifest?.proof?.jws) {
    return { ok: false, error: "manifest missing proof.jws" };
  }
  let jwks = null;
  if (signingKeyUrl) {
    const resp = await fetchImpl(signingKeyUrl, { headers: { Accept: "application/json" } });
    if (resp.ok) jwks = await resp.json();
  }
  if (!jwks?.keys?.length) {
    return { ok: false, error: "no signing keys available to verify manifest" };
  }
  try {
    const keySet = jose.createLocalJWKSet(jwks);
    await jose.compactVerify(manifest.proof.jws, keySet);
    return { ok: true };
  } catch (err) {
    return { ok: false, error: `manifest signature invalid: ${err.message}` };
  }
}

function decodeJwt(credential) {
  const parts = credential.split(".");
  if (parts.length !== 3) throw new Error("not a compact JWS");
  const header = JSON.parse(Buffer.from(parts[0], "base64url").toString("utf8"));
  const payload = JSON.parse(Buffer.from(parts[1], "base64url").toString("utf8"));
  return { header, payload };
}

function detectProfile(header, payload) {
  if (Array.isArray(header.x5c) && header.x5c.length > 0) return "tier2-x509-jwt";
  if (typeof payload.iss === "string" && payload.iss.startsWith("did:")) return "tier3-vc-jose";
  if (payload.vc && typeof payload.vc === "object") return "tier3-vc-jose";
  return "tier1-jwt";
}

function collectConstraintTypes(payload) {
  const constraints = payload.constraints || payload.termsOfUse || [];
  return [...new Set(constraints.map((c) => c.type).filter(Boolean))];
}

function collectVocabularyFields(payload) {
  const constraints = payload.constraints || payload.termsOfUse || [];
  const fields = new Set();
  for (const c of constraints) {
    if (typeof c.field === "string" && SEMANTIC_PREFIXES.some((p) => c.field.startsWith(p))) {
      fields.add(c.field);
    }
  }
  return [...fields];
}

export function checkProfile(profile, manifest) {
  const supported = (manifest.credentialProfiles || []).map((p) => p.id);
  if (!supported.includes(profile)) {
    return { rule: "profileMatch", severity: "error", detail: `credential profile ${profile} not in manifest.credentialProfiles` };
  }
  return null;
}

export function checkConstraintTypes(types, manifest) {
  const supported = new Set(manifest.constraintTypes || []);
  const missing = types.filter((t) => !supported.has(t));
  if (missing.length > 0) {
    return { rule: "constraintTypes", severity: "error", detail: `unsupported constraint types: ${missing.join(", ")}` };
  }
  return null;
}

export function checkVocabulary(fields, manifest) {
  const all = new Set();
  const recognized = manifest.recognizedFields || {};
  for (const key of Object.keys(recognized)) {
    for (const f of recognized[key] || []) all.add(f);
  }
  for (const profile of manifest.mappingProfiles || []) {
    for (const f of Object.keys(profile.fields || {})) all.add(f);
  }
  const missing = fields.filter((f) => !all.has(f));
  if (missing.length > 0) {
    return { rule: "vocabulary", severity: "error", detail: `unrecognized vocabulary fields: ${missing.join(", ")}` };
  }
  return null;
}

export function checkTrustAnchors(profile, issuer, manifest) {
  const anchors = manifest.acceptedTrustAnchors || {};
  if (profile === "tier1-jwt") {
    const known = (anchors.tier1?.trustedIssuers || []).map((t) => t.issuerId);
    if (known.length > 0 && !known.includes(issuer)) {
      return { rule: "trustAnchors", severity: "warning", detail: `issuer ${issuer} not pre-registered as tier1 trust anchor` };
    }
  }
  if (profile === "tier3-vc-jose") {
    const known = (anchors.tier3?.trustedIssuers || []).map((t) => t.issuerId);
    if (known.length > 0 && !known.includes(issuer)) {
      return { rule: "trustAnchors", severity: "warning", detail: `issuer ${issuer} not pre-registered as tier3 trust anchor` };
    }
  }
  return null;
}

export function checkRequiredContextFields(required, supplied) {
  const missing = (required || []).filter((f) => !supplied || !(f in supplied));
  if (missing.length > 0) {
    return { rule: "requiredContextFields", severity: "error", detail: `requestContext missing required fields: ${missing.join(", ")}` };
  }
  return null;
}

export async function preflightCheck({ manifestUrl, manifest, credential, requestContext, fetchImpl, signingKeyUrl, verify = true }) {
  let m = manifest;
  if (!m) {
    if (!manifestUrl) throw new Error("either manifest or manifestUrl is required");
    m = await fetchManifest(manifestUrl, { fetchImpl });
  }

  if (verify && signingKeyUrl) {
    const v = await verifyManifest(m, { fetchImpl, signingKeyUrl });
    if (!v.ok) {
      return { compatible: false, incompatibilities: [{ rule: "manifestSignature", severity: "error", detail: v.error }] };
    }
  }

  const { header, payload } = decodeJwt(credential);
  const profile = detectProfile(header, payload);
  const types = collectConstraintTypes(payload);
  const fields = collectVocabularyFields(payload);
  const issuer = payload.iss;

  const incompatibilities = [
    checkProfile(profile, m),
    checkConstraintTypes(types, m),
    checkVocabulary(fields, m),
    checkTrustAnchors(profile, issuer, m),
    checkRequiredContextFields(m.requiredContextFields, requestContext),
  ].filter(Boolean);

  const errorCount = incompatibilities.filter((i) => i.severity === "error").length;
  return { compatible: errorCount === 0, incompatibilities };
}
